Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬
    const printShiftReport = async (shift: any) => {
        if (!settings?.printerAddress || !settings?.printerType) {
            Alert.alert('Info', 'Belum ada printer yang dikonfigurasi.');
            return;
        }
        try {
            const storeName = settings.storeName || 'LitePOS';
            const LINE = '--------------------------------\n';
            const W = 32;
            const center = (s: string) => { const p = Math.max(0, Math.floor((W - s.length) / 2)); return ' '.repeat(p) + s; };
            const padEnd = (s: string, l: number) => (s + ' '.repeat(l)).substring(0, l);
            const padStart = (s: string, l: number) => (' '.repeat(l) + s).slice(-l);
            const openTime = new Date(shift.openedAt);
            const closeTime = shift.closedAt ? new Date(shift.closedAt) : null;
            const durationMs = closeTime ? closeTime.getTime() - openTime.getTime() : Date.now() - openTime.getTime();
            const dH = Math.floor(durationMs / 3600000);
            const dM = Math.floor((durationMs % 3600000) / 60000);
            const diff = shift.closingCash != null ? shift.closingCash - (shift.openingCash + (shift.txTotal || 0) - (shift.expensesTotal || 0)) : null;

            let text = center(storeName) + '\n';
            text += center('LAPORAN SHIFT') + '\n';
            text += LINE;
            text += padEnd('Kasir', W - 14) + padStart(shift.userName || 'Kasir', 14) + '\n';
            text += padEnd('Buka', W - 14) + padStart(openTime.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' }), 14) + '\n';
            if (closeTime) text += padEnd('Tutup', W - 14) + padStart(closeTime.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' }), 14) + '\n';
            text += padEnd('Durasi', W - 14) + padStart(`${dH}j ${dM}m`, 14) + '\n';
            text += LINE;
            text += padEnd('Kas Awal', W - 14) + padStart(formatRp(shift.openingCash || 0), 14) + '\n';
            text += padEnd('Total Penjualan', W - 14) + padStart(formatRp(shift.txTotal || 0), 14) + '\n';
            text += padEnd('Pengeluaran', W - 14) + padStart(formatRp(shift.expensesTotal || 0), 14) + '\n';
            text += padEnd('Jml Transaksi', W - 14) + padStart(String(shift.txCount || 0), 14) + '\n';
            if (shift.closingCash != null) text += padEnd('Kas Akhir', W - 14) + padStart(formatRp(shift.closingCash), 14) + '\n';
            if (diff !== null) text += padEnd('Selisih Kas', W - 14) + padStart(`${diff >= 0 ? '+' : ''}${formatRp(diff)}`, 14) + '\n';
            text += LINE;
            text += center(`Dicetak: ${new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' })}`) + '\n\n\n';

            const hasPerms = await requestPrinterPermissions();
            if (!hasPerms && settings.printerType === 'BLE') {
                Alert.alert('Izin Ditolak', 'Dibutuhkan izin Bluetooth untuk mencetak.');
                return;
            }

            const printerClass = settings.printerType === 'USB' ? USBPrinter : BLEPrinter;
            try { await printerClass.init(); } catch { }
            try {
                if (settings.printerType === 'BLE') await printerClass.connectPrinter(settings.printerAddress);
                else { const [v, p] = settings.printerAddress.split('|'); await printerClass.connectPrinter(Number(v), Number(p)); }
            } catch { }
            await printerClass.printText(text);
        } catch (e) {
            Alert.alert('Error', 'Gagal mencetak. Pastikan printer tersambung.');
        }
    };

