    const CategoryContent = () => (
        <ScrollView contentContainerStyle={tw`p-4 pb-24`}>
            {/* Summary header */}
            <View style={tw`bg-blue-600 p-4 rounded-2xl mb-4`}>
                <Text style={tw`text-blue-100 font-bold text-xs uppercase mb-1`}>Total Penjualan (Bruto)</Text>
                <Text style={tw`text-white font-black text-xl`}>{formatRp(summary.bruto)}</Text>
                <Text style={tw`text-blue-200 text-[10px] mt-1`}>{summary.count} Transaksi</Text>
            </View>

            {categoryStats.length === 0 ? (
                <View style={tw`items-center py-16`}>
                    <Text style={tw`text-gray-400 font-bold`}>Belum ada data kategori</Text>
                </View>
            ) : (
                <View style={tw`bg-white dark:bg-gray-800 p-4 rounded-2xl border border-gray-100 dark:border-gray-800`}>
                    <Text style={tw`font-bold text-gray-700 dark:text-gray-200 mb-3 text-sm`}>Pendapatan per Kategori</Text>
                    {categoryStats.map((cat, idx) => {
                        const maxTotal = categoryStats[0]?.total || 1;
                        const pct = Math.max(4, (cat.total / maxTotal) * 100);
                        return (
                            <View key={idx} style={tw`mb-4`}>
                                <View style={tw`flex-row justify-between mb-1`}>
                                    <Text style={tw`font-bold text-gray-800 dark:text-gray-100 text-sm flex-1 mr-2`} numberOfLines={1}>
                                        {idx + 1}. {cat.name}
                                    </Text>
                                    <Text style={tw`text-blue-600 font-black text-sm`}>{formatRp(cat.total)}</Text>
                                </View>
                                <View style={tw`h-7 bg-gray-100 dark:bg-gray-700 rounded-full overflow-hidden`}>
                                    <View style={[tw`h-full rounded-full items-center justify-center`, { width: `${pct}%`, backgroundColor: tw.color(`blue-${Math.max(3, 7 - idx) * 100 > 900 ? 900 : Math.max(3, 7 - idx) * 100}`) || tw.color('blue-500') }]}>
                                        <Text style={tw`text-white text-[9px] font-black px-1`} numberOfLines={1}>{cat.count} trx</Text>
                                    </View>
                                </View>
                            </View>
                        );
                    })}
                </View>
            )}
        </ScrollView>
    );

