    const ProfitContent = () => (
        <ScrollView contentContainerStyle={tw`p-4 pb-24`}>
            <View style={tw`bg-green-600 p-4 rounded-2xl mb-4 flex-row items-center`}>
                <View style={tw`flex-1`}>
                    <Text style={tw`text-green-100 font-bold text-xs uppercase mb-1`}>Keuntungan Bersih (Profit)</Text>
                    <Text style={tw`text-white font-black text-2xl`}>{formatRp(summary.neto - summary.cogs)}</Text>
                </View>
                <Icon name="currency-usd" size={32} color="rgba(255,255,255,0.4)" />
            </View>

            <View style={tw`bg-white dark:bg-gray-800 rounded-2xl p-4 border border-gray-100 dark:border-gray-800`}>
                <View style={tw`flex-row justify-between mb-3`}>
                    <Text style={tw`text-gray-500 dark:text-gray-400 text-sm font-bold`}>Penjualan Kotor (Bruto)</Text>
                    <Text style={tw`text-gray-800 dark:text-gray-100 text-sm font-black`}>{formatRp(summary.bruto)}</Text>
                </View>
                <View style={tw`flex-row justify-between mb-3`}>
                    <Text style={tw`text-gray-500 dark:text-gray-400 text-sm font-bold`}>Diskon</Text>
                    <Text style={tw`text-yellow-600 text-sm font-black`}>- {formatRp(summary.discounts)}</Text>
                </View>
                <View style={tw`flex-row justify-between mb-3 pb-3 border-b border-gray-100 dark:border-gray-700`}>
                    <Text style={tw`text-gray-500 dark:text-gray-400 text-sm font-bold`}>Retur</Text>
                    <Text style={tw`text-red-500 text-sm font-black`}>- {formatRp(summary.returns)}</Text>
                </View>
                <View style={tw`flex-row justify-between mb-3`}>
                    <Text style={tw`text-gray-800 dark:text-gray-100 text-sm font-black`}>Penjualan Bersih (Neto)</Text>
                    <Text style={tw`text-blue-600 text-sm font-black`}>{formatRp(summary.neto)}</Text>
                </View>
                <View style={tw`flex-row justify-between mb-4 pb-4 border-b border-gray-100 dark:border-gray-700`}>
                    <Text style={tw`text-gray-500 dark:text-gray-400 text-sm font-bold`}>Harga Pokok Penjualan (HPP)</Text>
                    <Text style={tw`text-red-500 text-sm font-black`}>- {formatRp(summary.cogs)}</Text>
                </View>
                <View style={tw`flex-row justify-between`}>
                    <Text style={tw`text-gray-800 dark:text-gray-100 text-lg font-black`}>Laba Bersih</Text>
                    <Text style={tw`text-green-600 text-lg font-black`}>{formatRp(summary.neto - summary.cogs)}</Text>
                </View>
                
                {summary.neto > 0 && (
                    <View style={tw`mt-4 bg-gray-50 dark:bg-gray-900 rounded-xl p-3 flex-row justify-center items-center`}>
                        <Text style={tw`text-xs text-gray-500 dark:text-gray-400 font-bold mr-2`}>Margin Laba (Profit Margin):</Text>
                        <Text style={tw`text-sm text-green-600 font-black`}>{Math.round(((summary.neto - summary.cogs) / summary.neto) * 100)}%</Text>
                    </View>
                )}
            </View>
        </ScrollView>
    );

